                new LanguagePackSeedEntry(20169, "Help_Options_Logging_Text", "Write all ping responses to a text file. The file will be named <hostname>.txt and will be saved to the specified directory. If the file already exists, new output will be appended to the existing file.", "Zapísať všetky odpovede pingovania do textového súboru. Súbor bude pomenovaný <hostname>.txt a bude uložený v zadanom adresári. Ak súbor už existuje, nový výstup sa pripojí k existujúcemu súboru."),
                new LanguagePackSeedEntry(20170, "Help_Options_PingInterval_Sub", "Ping interval", "Interval pingovania"),
                new LanguagePackSeedEntry(20171, "Help_Options_PingInterval_Text", "The time to wait between sending each packet. The time can be specified in seconds, minutes, or hours.", "Čas čakania medzi odosielaním jednotlivých paketov. Čas môže byť zadaný v sekundách, minútach alebo hodinách."),
                new LanguagePackSeedEntry(20172, "Help_Options_PingTimeout_Sub", "Ping timeout", "Časový limit pingovania"),
                new LanguagePackSeedEntry(20173, "Help_Options_PingTimeout_Text", "The maximum time to wait for a response, in seconds.", "Maximálny čas čakania na odpoveď v sekundách."),
                new LanguagePackSeedEntry(20174, "Help_Options_PortableConfig_Sub", "Portable configuration", "Prenosná konfigurácia"),
                new LanguagePackSeedEntry(20175, "Help_Options_PortableConfig_Text", "All settings are stored in a MultiPingMonitor.xml file located next to the executable. This makes the application fully portable — just copy the folder to another location or USB drive.", "Všetky nastavenia sú uložené v súbore MultiPingMonitor.xml vedľa spustiteľného súboru. Vďaka tomu je aplikácia plne prenosná — stačí skopírovať priečinok na iné miesto alebo USB disk."),
                new LanguagePackSeedEntry(20176, "Help_Options_StartInTray_Sub", "Start in tray", "Spustenie v tray"),
                new LanguagePackSeedEntry(20177, "Help_Options_StartInTray_Text", "When enabled in Settings, MultiPingMonitor starts minimized to the system tray instead of showing the main window. Pinging begins immediately in the background. Double-click the tray icon to restore the window.", "Keď je táto možnosť povolená v Nastaveniach, MultiPingMonitor sa spustí minimalizovaný do systémovej lišty namiesto zobrazenia hlavného okna. Pingovanie začne okamžite na pozadí. Dvojklikom na ikonu v tray obnovíte okno."),
                new LanguagePackSeedEntry(20178, "Help_Options_TrayBehavior_Sub", "System tray", "Systémová lišta"),
                new LanguagePackSeedEntry(20179, "Help_Options_TrayBehavior_Text", "When the main window is closed, MultiPingMonitor minimizes to the system tray and continues pinging in the background. Right-click the tray icon to access options such as Open, New Instance, Status History, Options, and Exit.", "Po zatvorení hlavného okna sa MultiPingMonitor minimalizuje do systémovej lišty a pokračuje v pingovaní na pozadí. Kliknutím pravým tlačidlom na ikonu v tray získate prístup k položkám ako Otvoriť, Nová inštancia, História stavov, Nastavenia a Ukončiť."),
                new LanguagePackSeedEntry(20180, "Help_PortMonitor_Sub", "Port Monitor", "Monitor portu"),
                new LanguagePackSeedEntry(20181, "Help_PortMonitor_Text_After", ", will monitor port 80 on SERVER01.", ", bude monitorovať port 80 na SERVER01."),
                new LanguagePackSeedEntry(20182, "Help_PortMonitor_Text_Before", "To monitor a specific TCP port, simply enter the hostname or IP address followed by a colon and the desired port number. MultiPingMonitor will then continuously try to connect to the given port and display whether or not the connection is successful. Example -", "Ak chcete monitorovať konkrétny TCP port, zadajte názov hostiteľa alebo IP adresu, za ňou dvojbodku a požadované číslo portu. MultiPingMonitor sa potom nepretržite pokúša pripojiť na daný port a zobrazuje, či je spojenie úspešné. Príklad -"),
                new LanguagePackSeedEntry(20183, "Help_Title", "MultiPingMonitor Help", "Pomocník MultiPingMonitor"),
